const normalizeArray = (value) => {
  if (Array.isArray(value)) return value;
  if (typeof value === 'string' && value.trim()) {
    try {
      const parsed = JSON.parse(value);
      if (Array.isArray(parsed)) return parsed;
    } catch {}

    return value
      .replace(/^\{/, '')
      .replace(/\}$/, '')
      .split(',')
      .map((entry) => entry.trim())
      .filter(Boolean);
  }
  return [];
};

const topic = $('Postgres : Réserver 1 Sujet SEO').first().json;
const selection = items[0]?.json ?? {};

const rawProducts = normalizeArray(selection.products).map((product) => {
  if (typeof product === 'string') {
    try {
      return JSON.parse(product);
    } catch {
      return null;
    }
  }
  return product;
}).filter(Boolean);

const rawProductIds = normalizeArray(selection.product_ids).map((id) => String(id)).filter(Boolean);
const uniqueProductIds = [...new Set(rawProductIds)];

const productsText = rawProducts.length > 0
  ? rawProducts
      .map((product) => `- ${product.title} (Prix indicatif : ${product.retail_price ?? 'N/A'}€)`)
      .join('\n')
  : 'Aucun produit imposé pour ce sujet. Utilise une recommandation très légère ou aucune si ce n'est pas pertinent.';

return [{
  json: {
    topic_id: topic.id,
    topic_title: topic.title,
    target_keyword: topic.target_keyword || '',
    secondary_keywords: topic.secondary_keywords || '',
    search_intent: topic.search_intent || 'informational',
    pillar: topic.pillar || '',
    article_type: topic.article_type || 'guide',
    angle: topic.angle || '',
    audience: topic.audience || '',
    brief: topic.brief || '',
    seasonality: topic.seasonality || 'evergreen',
    min_words: Number(topic.min_words || 900),
    max_products: Number(topic.max_products || 4),
    products: rawProducts,
    products_text: productsText,
    product_ids: uniqueProductIds,
    cover_image: selection.cover_image || null,
  }
}];

